    35→// initAppender is a helper to initialize the time bounds of the head
    36→// upon the first sample it receives.
    37→type initAppender struct {
    38→	app  storage.Appender
    39→	head *Head
    40→}
    41→
    42→var _ storage.GetRef = &initAppender{}
    43→
    44→func (a *initAppender) SetOptions(opts *storage.AppendOptions) {
    45→	if a.app != nil {
    46→		a.app.SetOptions(opts)
    47→	}
    48→}
    49→
    50→func (a *initAppender) Append(ref storage.SeriesRef, lset labels.Labels, t int64, v float64) (storage.SeriesRef, error) {
    51→	if a.app != nil {
    52→		return a.app.Append(ref, lset, t, v)
    53→	}
    54→
    55→	a.head.initTime(t)
    56→	a.app = a.head.appender()
    57→	return a.app.Append(ref, lset, t, v)
    58→}
    59→
    60→func (a *initAppender) AppendExemplar(ref storage.SeriesRef, l labels.Labels, e exemplar.Exemplar) (storage.SeriesRef, error) {
    61→	// Check if exemplar storage is enabled.
    62→	if !a.head.opts.EnableExemplarStorage || a.head.opts.MaxExemplars.Load() <= 0 {
    63→		return 0, nil
    64→	}
    65→
    66→	if a.app != nil {
    67→		return a.app.AppendExemplar(ref, l, e)
    68→	}
    69→	// We should never reach here given we would call Append before AppendExemplar
    70→	// and we probably want to always base head/WAL min time on sample times.
    71→	a.head.initTime(e.Ts)
    72→	a.app = a.head.appender()
    73→
    74→	return a.app.AppendExemplar(ref, l, e)
    75→}
    76→
    77→func (a *initAppender) AppendHistogram(ref storage.SeriesRef, l labels.Labels, t int64, h *histogram.Histogram, fh *histogram.FloatHistogram) (storage.SeriesRef, error) {
    78→	if a.app != nil {
    79→		return a.app.AppendHistogram(ref, l, t, h, fh)
    80→	}
    81→	a.head.initTime(t)
    82→	a.app = a.head.appender()
    83→
    84→	return a.app.AppendHistogram(ref, l, t, h, fh)
    85→}
