    88→	if a.app != nil {
    89→		return a.app.AppendHistogramSTZeroSample(ref, l, t, st, h, fh)
    90→	}
    91→	a.head.initTime(t)
    92→	a.app = a.head.appender()
    93→
    94→	return a.app.AppendHistogramSTZeroSample(ref, l, t, st, h, fh)
    95→}
    96→
