    98→	if a.app != nil {
    99→		return a.app.UpdateMetadata(ref, l, m)
   100→	}
   101→
   102→	a.app = a.head.appender()
   103→	return a.app.UpdateMetadata(ref, l, m)
   104→}
   105→
   106→func (a *initAppender) AppendSTZeroSample(ref storage.SeriesRef, lset labels.Labels, t, st int64) (storage.SeriesRef, error) {
   107→	if a.app != nil {
   108→		return a.app.AppendSTZeroSample(ref, lset, t, st)
   109→	}
   110→
   111→	a.head.initTime(t)
   112→	a.app = a.head.appender()
   113→
   114→	return a.app.AppendSTZeroSample(ref, lset, t, st)
   115→}
   116→
   117→// initTime initializes a head with the first timestamp. This only needs to be called
   118→// for a completely fresh head with an empty WAL.
   119→func (h *Head) initTime(t int64) {
   120→	if !h.minTime.CompareAndSwap(math.MaxInt64, t) {
   121→		// Concurrent appends that are initializing.
   122→		// Wait until h.maxTime is swapped to avoid minTime/maxTime races.
   123→		antiDeadlockTimeout := time.After(500 * time.Millisecond)
   124→		for h.maxTime.Load() == math.MinInt64 {
   125→			select {
   126→			case <-antiDeadlockTimeout:
   127→				return
   128→			default:
   129→			}
   130→		}
   131→		return
   132→	}
   133→	// Ensure that max time is initialized to at least the min time we just set.
   134→	h.maxTime.CompareAndSwap(math.MinInt64, t)
   135→}
   136→
   137→func (a *initAppender) GetRef(lset labels.Labels, hash uint64) (storage.SeriesRef, labels.Labels) {
   138→	if g, ok := a.app.(storage.GetRef); ok {
   139→		return g.GetRef(lset, hash)
   140→	}
   141→	return 0, labels.EmptyLabels()
   142→}
